func uptimeMessageClass(message UptimeMessage) string {
	if message.Kind == "error" {
		return "notice notice--error"
	}

	return "notice notice--success"
}

func uptimeStateChipClass(state string) string {
	if state == "up" {
		return "chip chip--ok"
	}

	if state == "down" {
		return "chip chip--error"
	}

	return "chip chip--debug"
}

func uptimeMonitorCountLabel(view uptimeapp.View) string {
	if len(view.Monitors) == 1 {
		return "1 monitor"
	}

	return fmt.Sprintf("%d monitors", len(view.Monitors))
}

func statusPageCountLabel(view uptimeapp.View) string {
	if len(view.StatusPages) == 1 {
		return "1 page"
	}

	return fmt.Sprintf("%d pages", len(view.StatusPages))
}

func statusPageLink(page uptimeapp.StatusPageSummaryView) string {
	if page.PublicPath != "" {
		return page.PublicPath
	}

	return page.PrivatePath
}

func uptimeMonitorTarget(monitor uptimeapp.MonitorView) string {
	if monitor.CheckInPath != "" {
		return monitor.CheckInPath
	}

	return monitor.URL
}

func uptimeMonitorGrace(monitor uptimeapp.MonitorView) string {
	if monitor.Grace == "" {
		return "-"
	}

	return monitor.Grace
}

func uptimeMonitorTimeout(monitor uptimeapp.MonitorView) string {
	if monitor.Kind == "heartbeat" {
		return "-"
	}

	return monitor.Timeout
}

func uptimeLastCheckText(monitor uptimeapp.MonitorView) string {
	if monitor.LastError != "" {
		return monitor.LastError
	}

	if monitor.Kind == "heartbeat" && monitor.LastCheckInAt != "" {
		return "check-in " + monitor.LastCheckInAt
	}

	if monitor.LastStatusCode != "" {
		return "HTTP " + monitor.LastStatusCode
	}

	return "not checked"
}

